	// If the webhook expects a test payload, this might fail.
	// Alternative: Use query parameters or send empty GET request.

	// Send GET request to webhook URL
	reqGet, err := http.NewRequest("GET", req.WebhookURL, bytes.NewReader(jsonPayload))
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to create GET request: %v", err),
		})
	}

	// Set appropriate headers if needed
	reqGet.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(reqGet)
	if err != nil {
