		Message: "Webhook test from server",
	}

	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Internal server error",
		})
	}

	// Create HTTP request with context
	httpReq, err := http.NewRequestWithContext(reqCtx, "POST", req.WebhookURL, strings.NewReader(string(payloadBytes)))
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL",
		})
	}

	// Set headers
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Accept", "application/json")

	// Send test request to webhook URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Generic error message to avoid information disclosure
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
			"success": true,
			"message": "Webhook configured successfully",
		})
	}

	// Return error for non-2xx responses
	return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
		"success": false,
		"error":   "Webhook URL validation failed",
	})
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(host string) bool {
	// First check if it's a common blocked hostname
	if strings.Contains(host, "localhost") ||
		strings.Contains(host, "127.0.0.1") ||
		strings.Contains(host, "::1") ||
		strings.Contains(host, "0.0.0.0") {
		return true
	}

	// Try to parse as IP first
	ip := net.ParseIP(host)
	if ip != nil {
		return isPrivateIPAddr(ip)
	}

	// If it's not an IP, it's a hostname - we'll check during DialContext
	return false
}

// isPrivateIPAddr checks if an IP address is in private ranges
func isPrivateIPAddr(ip net.IP) bool {
	// Check for private IP ranges
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	ip4 := ip.To4()
	if ip4 != nil {
		// Check RFC 1918 private addresses
		if ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) {
			return true
		}
		// Check carrier-grade NAT
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
		// Check localhost variations
		if ip4[0] == 127 {
			return true
		}
	}

	return false
}

