// isInternalIP checks if an IP address is in a private/internal range
func isInternalIP(ip net.IP) bool {
	// Check for private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			ip4[0] == 127 || // 127.0.0.0/8 (localhost)
			ip4[0] == 0 // 0.0.0.0/8
	}

	// Check for IPv6 private ranges
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for IPv6 private addresses (fc00::/7)
	if len(ip) == 16 && ip[0] == 0xfc {
		return true
	}

	return false
}

// resolveAndValidateURL resolves the URL and checks if it points to internal IPs
func resolveAndValidateURL(rawURL string) error {
	parsedURL, err := url.ParseRequestURI(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use https scheme for security")
	}

	// Resolve the hostname to check IP addresses
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("invalid hostname")
	}

	// Prevent DNS rebinding by resolving before making the request
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("could not resolve hostname")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isInternalIP(ip) {
			return fmt.Errorf("webhook URL cannot point to internal/private IP addresses")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
