// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ip net.IP) bool {
	// Check for private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			(ip4[0] == 169 && ip4[1] == 254) || // APIPA
			(ip4[0] == 127) // localhost
	}

	// Check for private IPv6 ranges
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() ||
		strings.HasPrefix(ip.String(), "fd") || // Unique Local Addresses (ULA)
		strings.HasPrefix(ip.String(), "fc") // ULA
}

// validateWebhookURL performs security checks on the URL
func validateWebhookURL(urlStr string) error {
	parsedURL, err := url.ParseRequestURI(urlStr)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Resolve host to IP address for validation
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("invalid host")
	}

	// Skip validation for localhost/127.0.0.1 if needed, or reject it
	// For security, we'll reject localhost addresses
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return fmt.Errorf("localhost addresses are not allowed")
	}

	// Resolve IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("could not resolve host")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("private IP addresses are not allowed")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL for security
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with timeout and redirect restrictions
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Prevent redirects to avoid SSRF chains
			return http.ErrUseLastResponse
		},
		Transport: &http.Transport{
			// Disable keep-alives to prevent connection reuse attacks
			DisableKeepAlives: true,
			// Limit response sizes
			ResponseHeaderTimeout: 2 * time.Second,
		},
	}

	// Prepare test payload (variable is declared but not used - we'll remove the unused variable)
	// The payload is used for GET request with query parameter instead
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	_, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Internal server error",
		})
	}

