	// The test expects GET request with query parameters, not POST with body
	parsedURL, _ := url.Parse(req.WebhookURL)
	q := parsedURL.Query()
	q.Set("message", "Webhook configuration test")
	parsedURL.RawQuery = q.Encode()

	reqObj, err := http.NewRequest("GET", parsedURL.String(), nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL",
		})
	}

