type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles POST requests to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test request to validate webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (in a real implementation, this would persist to database)
	// For this example, we'll just log it
	fmt.Printf("Webhook configuration saved successfully: %s\n", config.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create Fiber app
