// Helper function to check if IP is private/internal
func isPrivateIP(host string) bool {
	// Check for common private IP patterns and localhost
	privatePatterns := []string{
		"localhost",
		"127.",
		"192.168.",
		"10.",
		"172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.",
		"172.24.", "172.25.", "172.26.", "172.27.",
		"172.28.", "172.29.", "172.30.", "172.31.",
		"169.254.", // Link-local
		"::1",      // IPv6 localhost
		"fc00::",   // IPv6 private
		"fd00::",   // IPv6 private
		"fe80::",   // IPv6 link-local
	}

	for _, pattern := range privatePatterns {
		if len(host) >= len(pattern) && host[:len(pattern)] == pattern {
			return true
		}
	}
	return false
}

// Helper function to resolve hostname
func resolveHost(hostname string) (string, error) {
	// Simple implementation - in production use net.LookupHost
	// This is a placeholder for the actual DNS resolution
	return hostname, nil
}

// Helper function to sanitize URL before storage
func sanitizeURL(rawURL string) string {
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return ""
	}

	// Remove any sensitive information like passwords
	if parsed.User != nil {
		parsed.User = nil
	}

	// Remove fragments
	parsed.Fragment = ""

	return parsed.String()
}

