// WebhookConfig represents the incoming request structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	Details string `json:"details,omitempty"`
}

// ConfigureWebhook handles the webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body",
			Details: err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Test the webhook URL with a GET request
	testResult, err := testWebhookURL(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL validation failed",
			Details: err.Error(),
		})
	}

	// Save the configuration (in a real application, this would persist to database/file)
	if err := saveWebhookConfig(config); err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to save webhook configuration",
			Details: err.Error(),
		})
	}

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		Details: fmt.Sprintf("Test request succeeded with status: %d", testResult.StatusCode),
	})
}

// testWebhookURL sends a GET request to validate the webhook URL
func testWebhookURL(url string) (*http.Response, error) {
	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request
	resp, err := client.Get(url)
	if err != nil {
		return nil, fmt.Errorf("failed to send test request: %w", err)
	}
	defer resp.Body.Close()

	// Read response body to ensure complete response
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response body: %w", err)
	}

	// Check for successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return resp, fmt.Errorf("webhook returned non-success status: %d, body: %s", 
			resp.StatusCode, string(body))
	}

	return resp, nil
}

// saveWebhookConfig simulates saving the webhook configuration
func saveWebhookConfig(config WebhookConfig) error {
	// In a real application, this would save to a database or file
	// For this example, we'll just log and simulate success

	configJSON, err := json.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal config: %w", err)
	}

	fmt.Printf("Webhook configuration saved: %s\n", string(configJSON))
	return nil
}

func main() {
	// Create Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

