// webhookTestPayload is the payload sent to test the webhook
type webhookTestPayload struct {
	Message string `json:"message"`
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			ip4[0] == 127 || // 127.0.0.0/8 (loopback)
			ip4[0] == 0 || // 0.0.0.0/8
			(ip4[0] == 169 && ip4[1] == 254) // 169.254.0.0/16 (link-local)
	}
	// Check for IPv6 private ranges
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() ||
		ip.IsUnspecified() || strings.HasPrefix(ip.String(), "fc00") || // Unique Local Addresses
		strings.HasPrefix(ip.String(), "fd00") || // Unique Local Addresses
		strings.HasPrefix(ip.String(), "fe80") // Link-local addresses
}

// resolveAndValidateURL resolves and validates a URL to prevent SSRF
func resolveAndValidateURL(rawURL string) error {
	parsedURL, err := url.ParseRequestURI(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(parsedURL.Hostname())
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body with size limit
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL and prevent SSRF
	if err := resolveAndValidateURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with timeout and security settings
	client := &http.Client{
		Timeout: 10 * time.Second,
		Transport: &http.Transport{
			DisableKeepAlives: true,
			DialContext: (&net.Dialer{
				Timeout:   5 * time.Second,
				KeepAlive: -1,
			}).DialContext,
			TLSHandshakeTimeout: 5 * time.Second,
		},
	}

	// Prepare test payload
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Create request with context timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.WebhookURL, bytes.NewBuffer(jsonPayload))
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL",
		})
	}
	httpReq.Header.Set("Content-Type", "application/json")

	// Send test request to webhook URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non-success status",
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Add rate limiting middleware
	app.Use(limiter.New(limiter.Config{
		Max:        10, // 10 requests
		Expiration: 1 * time.Minute,
		KeyGenerator: func(c *fiber.Ctx) string {
			return c.IP()
		},
		LimitReached: func(c *fiber.Ctx) error {
			return c.Status(fiber.StatusTooManyRequests).JSON(fiber.Map{
				"success": false,
				"error":   "Rate limit exceeded",
			})
		},
	}))

	// Add request size limit middleware
	app.Use(func(c *fiber.Ctx) error {
		// Limit request body to 1MB
		if len(c.Body()) > 1024*1024 {
			return c.Status(fiber.StatusRequestEntityTooLarge).JSON(fiber.Map{
				"success": false,
				"error":   "Request too large",
			})
		}
		return c.Next()
	})

	app.Post("/configure-webhook", ConfigureWebhook)
	app.Listen(":3000")
}

