	"time"

	"github.com/gofiber/fiber/v2"
	"github.com/gofiber/fiber/v2/middleware/logger"
)

// WebhookConfig represents the incoming request structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the API response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

// In-memory storage for webhook configuration (for demonstration)
var currentWebhookURL string

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON payload",
		})
	}

	// Validate webhook URL format
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "URL must use http or https scheme",
		})
	}

	// Test the webhook URL with a GET request
	testResult, err := testWebhookURL(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook test failed: %v", err),
			URL:     config.WebhookURL,
		})
	}

	// Save the configuration (in-memory for this example)
	currentWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: fmt.Sprintf("Webhook configured successfully. Test response: %s", testResult),
		URL:     config.WebhookURL,
	})
}

// testWebhookURL sends a GET request to test the webhook URL
func testWebhookURL(url string) (string, error) {
	// Create context with 3-second timeout
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request with context
	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return "", fmt.Errorf("failed to create request: %w", err)
	}

	// Send HTTP request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return "", fmt.Errorf("failed to send request: %w", err)
	}
	defer resp.Body.Close()

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("failed to read response: %w", err)
	}

	// Check for successful response (2xx status codes)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return "", fmt.Errorf("received non-2xx status code: %d", resp.StatusCode)
	}

	return string(body), nil
}

// GetCurrentWebhook returns the currently configured webhook URL
func GetCurrentWebhook(ctx *fiber.Ctx) error {
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Current webhook configuration",
		URL:     currentWebhookURL,
	})
}

func main() {
	// Create Fiber app
	app := fiber.New()

	// Add logger middleware
	app.Use(logger.New())

	// Define routes
	app.Post("/webhook/configure", ConfigureWebhook)
	app.Get("/webhook/current", GetCurrentWebhook)

	// Health check endpoint
	app.Get("/health", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{
			"status":  "ok",
			"service": "webhook-configurator",
		})
	})

	// Start server
	fmt.Println("Server starting on :8080")
	if err := app.Listen(":8080"); err != nil {
		panic(err)
	}
}

