// isBlockedIP checks if an IP address should be blocked
func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check for localhost
	if ip.IsLoopback() {
		return true
	}

	// Check for private IP ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for AWS metadata service (169.254.169.254)
	if ip.Equal(net.IPv4(169, 254, 169, 254)) {
		return true
	}

	return false
}

// safeHTTPClient creates an HTTP client with SSRF protection
func safeHTTPClient() *http.Client {
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Split host and port
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				// If no port, use default
				host = addr
				port = "80"
				if strings.HasPrefix(addr, "https://") {
					port = "443"
				}
			}

			// Resolve IP address
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, fmt.Errorf("failed to resolve host: %v", err)
			}

			// Check all resolved IPs
			for _, ip := range ips {
				if isBlockedIP(ip) {
					return nil, fmt.Errorf("access to %s is blocked", ip.String())
				}
			}

			// Use the first resolved IP
			resolvedAddr := net.JoinHostPort(ips[0].String(), port)
			return dialer.DialContext(ctx, network, resolvedAddr)
		},
		DisableKeepAlives: true,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   3 * time.Second,
	}
}

