	reqURL := req.WebhookURL + "?test=" + url.QueryEscape(string(jsonPayload))
	request, err := http.NewRequest("GET", reqURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	// Set appropriate headers
	request.Header.Set("User-Agent", "WebhookConfigurator/1.0")
	request.Header.Set("Accept", "application/json")

	resp, err := client.Do(request)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance
	// Security: Validate and sanitize before saving
	sanitizedURL := sanitizeURL(req.WebhookURL)
	// db.SaveWebhookURL(sanitizedURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     sanitizedURL,
	})
}

// validateHost checks if the host is allowed
func validateHost(host string) error {
	// Remove port if present
	host = strings.Split(host, ":")[0]

	// Block localhost and loopback addresses
	if host == "localhost" || host == "127.0.0.1" || host == "::1" || host == "0.0.0.0" {
		return fmt.Errorf("localhost addresses are not allowed")
	}

	// Block internal/private domain patterns
	internalPatterns := []string{
		".local",
		".internal",
		".localdomain",
		".home",
		".lan",
	}

	for _, pattern := range internalPatterns {
		if strings.HasSuffix(host, pattern) {
			return fmt.Errorf("internal domains are not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			(ip4[0] == 169 && ip4[1] == 254) || // APIPA 169.254.0.0/16
			(ip4[0] == 127) // 127.0.0.0/8
	}

	// IPv6 private ranges
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv6 unique local addresses (fc00::/7)
	if len(ip) == 16 && ip[0] == 0xfc {
		return true
	}

	return false
}

// sanitizeURL performs basic URL sanitization
func sanitizeURL(urlStr string) string {
	// Remove any fragments
	if idx := strings.Index(urlStr, "#"); idx != -1 {
		urlStr = urlStr[:idx]
	}

	// Trim whitespace
	urlStr = strings.TrimSpace(urlStr)

	return urlStr
}

